// Merge DB session with original message data
const extractData = $('Extraer Datos').first().json;
const dbItems = $input.all();

// Get message (text or transcribed audio)
let mensaje = extractData.mensaje || '';
try {
  const audioData = $('Armar Mensaje de Audio').first().json;
  if (audioData?.mensaje) mensaje = audioData.mensaje;
} catch(e) { /* text path */ }

// Parse DB session
let intent_db = 'UNKNOWN';
let history = [];
if (dbItems.length > 0 && dbItems[0].json && dbItems[0].json.phone) {
  const row = dbItems[0].json;
  intent_db = row.intent || 'UNKNOWN';
  const raw = row.history;
  if (Array.isArray(raw)) history = raw;
  else if (typeof raw === 'string') { try { history = JSON.parse(raw); } catch(e) { history = []; } }
  else if (raw && typeof raw === 'object') history = Object.values(raw).length ? raw : [];
}

// tiene_sesion = true solo si ya existe sesión con intent definido
const tiene_sesion = (intent_db === 'COMPRADOR' || intent_db === 'VENDEDOR');

// Compute date context (Guayaquil UTC-5)
const ahora = new Date();
const offset = -5 * 60;
const local = new Date(ahora.getTime() + ahora.getTimezoneOffset() * 60000 + offset * 60000);
const dias = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
function iso(d) { return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`; }
function add(d,n) { const r=new Date(d); r.setDate(r.getDate()+n); return r; }
function next(t) { const h=local.getDay(); let d=t-h; if(d<=0)d+=7; return add(local,d); }
const man=add(local,1), pas=add(local,2);
const lun=next(1),mar=next(2),mie=next(3),jue=next(4),vie=next(5),sab=next(6),dom=next(0);

// Build history text (for agents)
const recientes = history.slice(-10);
let prompt_extra = '';
if (recientes.length > 0) {
  prompt_extra = '\n\n[Conversación previa]\n' +
    recientes.map(m => (m.role === 'human' ? 'Cliente: ' : 'Asistente: ') + m.content).join('\n') +
    '\n[Fin conversación previa]';
}

// Full date context string
const lunes=iso(lun), martes=iso(mar), miercoles=iso(mie), jueves=iso(jue), viernes=iso(vie), sabado=iso(sab), domingo=iso(dom);
const fecha_contexto = `🗓️ CONTEXTO DE FECHAS (uso interno - nunca mencionar al cliente):\nHoy: ${dias[local.getDay()]} ${local.getDate()} de ${meses[local.getMonth()]} de ${local.getFullYear()} [${iso(local)}]\nMañana: ${dias[man.getDay()]} ${man.getDate()} de ${meses[man.getMonth()]} [${iso(man)}]\nPasado mañana: [${iso(pas)}]\nEsta semana: lunes=${lunes}, martes=${martes}, miércoles=${miercoles}, jueves=${jueves}, viernes=${viernes}, sábado=${sabado}, domingo=${domingo}\nPróxima semana: lunes=${iso(add(lun,7))}, martes=${iso(add(mar,7))}, miércoles=${iso(add(mie,7))}, jueves=${iso(add(jue,7))}, viernes=${iso(add(vie,7))}, sábado=${iso(add(sab,7))}, domingo=${iso(add(dom,7))}`;

return [{ json: {
  mensaje,
  numero:        extractData.numero,
  nombre:        extractData.nombre || '',
  phoneNumberId: extractData.phoneNumberId,
  intent_db,
  tiene_sesion,
  history_json:  JSON.stringify(history.slice(-20)),
  fecha_contexto,
  prompt_extra
}}];

// Clasificar Intent — solo para usuarios con sesión existente
// Los números nuevos van directo al Agente Comprador sin pasar por aquí
const d = $input.first().json;
const msg = (d.mensaje || '').toLowerCase();

// Keywords que pueden reclasificar incluso a usuarios con sesión
const venderKW = ['vender','vendo','quiero vender','tengo una propiedad','mi casa','mi departamento','mi terreno','mi suite','captacion','captación','poner en venta'];
const avaluoKW = ['avalúo','avaluo','valuación','valoración','valor de mi','cuánto vale','cuanto vale','precio de mi'];

// Partir del intent guardado (tiene_sesion=true aquí siempre)
let intent = d.intent_db;
if (avaluoKW.some(k => msg.includes(k)) || venderKW.some(k => msg.includes(k))) {
  intent = 'VENDEDOR';
} else if (!intent || intent === 'UNKNOWN') {
  intent = 'COMPRADOR';
}

return [{ json: { ...d, intent } }];

