// intent viene del Set node anterior (Marcar Comprador / Marcar Vendedor)
// history_json y mensaje vienen de Resolver Sesion (siempre corrió)
const d = $input.first().json;
const response = d.response || d.output || '';
const intent = d.intent || 'COMPRADOR';

const extractData = $('Extraer Datos').first().json;
const resolverData = $('Resolver Sesion').first().json;

const history = JSON.parse(resolverData.history_json || '[]');
history.push({ role: 'human', content: resolverData.mensaje });
history.push({ role: 'assistant', content: response });

return [{ json: {
  phone:         extractData.numero,
  nombre:        extractData.nombre || resolverData.nombre || '',
  intent,
  history_json:  JSON.stringify(history.slice(-20)),
  response,
  phoneNumberId: extractData.phoneNumberId
}}];
